import { test, expect } from '@fixtures/test';

// Footer content is identical for every user, so it is verified once as
// standard_user (@standard) rather than per-user.
test.describe('footer @standard', () => {
  test.describe('Positive', () => {
    // AC 1–3: each social link points to its canonical Sauce Labs URL.
    // Asserts the anchor's href — we don't navigate to the third-party sites.
    const socialLinks = [
      { network: 'twitter', label: 'Twitter', href: 'https://twitter.com/saucelabs' },
      { network: 'facebook', label: 'Facebook', href: 'https://www.facebook.com/saucelabs' },
      {
        network: 'linkedin',
        label: 'LinkedIn',
        href: 'https://www.linkedin.com/company/sauce-labs/',
      },
    ] as const;

    for (const { network, label, href } of socialLinks) {
      test(`footer ${label} link points to its Sauce Labs URL`, async ({ inventoryPage }) => {
        await inventoryPage.goto();
        expect(await inventoryPage.footer.getSocialLinkHref(network)).toBe(href);
      });
    }

    // AC 4: copyright line renders verbatim.
    test('footer shows the Sauce Labs copyright text', async ({ inventoryPage }) => {
      await inventoryPage.goto();
      expect(await inventoryPage.footer.getCopyrightText()).toBe(
        '© 2026 Sauce Labs. All Rights Reserved. Terms of Service | Privacy Policy',
      );
    });
  });
  // Negative + Edge describes omitted — footer content verification is all Positive.
});
